import ApiService, { ResponseType } from '@/api/api';
import { getTokenByBridge } from '@/utils';

export type Tasks = Array<{
  task_name: string;
  start_time: string;
  end_time: string;
  learn_capacity: string;
  reward_coin: number;
  sub_tasks: Array<{
    sub_task_id: string;
    sub_task_type: number;
    sub_task_name: string;
  }>;
}>;
type LearnScheduleDetailResponse = ResponseType<{
  schedule_name: string;
  schedule_desc: string;
  schedule_cover: string;
  start_time: number;
  end_time: number;
  grade: number;
  subject: number;
  tasks: Tasks;
  is_join_schedule: number;
}>;

type CreateLearnPlanRequestBody = {
  tal_id: string;
  report_id: number;
  str_workorder_id: string;
  weekly_rule: string;
  start_time: number;
  end_time: number;
  tasks: Array<{
    start_time: string;
    end_time: string;
    sub_tasks: Array<{
      sub_task_id: string;
      sub_task_type: number;
      sub_task_name: string;
    }>;
  }>;
};


export const getLearnScheduleDetail = async (obj: {
  tal_id: string;
  report_id: number;
}): LearnScheduleDetailResponse => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/study-schedule/learnsvc/detail', {
    ...obj,
    token
  });
};

export const createLearnPlan = async (obj: CreateLearnPlanRequestBody) => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/study-schedule/learnsvc/create', {
    ...obj,
    token
  });
};

// 将消息改为已读状态
export const changeMsgReadStatus = async (id: number) => {
  const token = await getTokenByBridge();
  return ApiService.post('/parent/api/v1/notice/set-read', {
    id,
    type: 1,
    token
  });
};
